        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter file name: ");
        String fileName = scanner.nextLine();

        // Securely construct the file path using Paths.get
        Path filePath = Path.of("/path/to/directory/", fileName).normalize();

        if (filePath.startsWith(Path.of("/path/to/directory/"))) {
